package com.sistema.puntoventas.controller;

import com.sistema.puntoventas.modelo.Usuario;
import com.sistema.puntoventas.service.UsuarioService;
import javafx.fxml.FXML;
import javafx.scene.control.Alert;
import javafx.scene.control.Button;
import javafx.scene.control.PasswordField;
import javafx.scene.control.TextField;
import javafx.stage.Stage;
import javafx.scene.Scene;
import javafx.fxml.FXMLLoader;
import javafx.scene.Parent;

public class LoginController {

    @FXML private TextField rutTextField;
    @FXML private PasswordField passwordField;
    @FXML private Button continuarButton;

    // Conectamos con el Service que ya tienes
    private final UsuarioService usuarioService = new UsuarioService();

    @FXML
    public void handleLogin() {
        String rut = rutTextField.getText().trim();
        String password = passwordField.getText().trim();

        if (rut.isEmpty() || password.isEmpty()) {
            mostrarAlerta(Alert.AlertType.WARNING, "Campos vacíos", "Ingresa RUT y contraseña.");
            return;
        }

        // Usamos tu método iniciarSesion del Service
        Usuario usuario = usuarioService.iniciarSesion(rut, password);

        if (usuario != null) {
            irAlMenuPrincipal(usuario);
        } else {
            mostrarAlerta(Alert.AlertType.ERROR, "Error de Inicio", "RUT o contraseña incorrectos.");
        }
    }

    private void irAlMenuPrincipal(Usuario usuarioLogueado) {
        try {
            // Carga la siguiente vista (Asegúrate que el nombre sea exacto)
            FXMLLoader loader = new FXMLLoader(getClass().getResource("/com/sistema/puntoventas/MenuPrincipal.fxml"));
            Parent root = loader.load();

            Stage stage = (Stage) continuarButton.getScene().getWindow();
            stage.setScene(new Scene(root));
            stage.setTitle("Sistema Eluney - Bienvenido " + usuarioLogueado.getNombre());
            stage.show();
        } catch (Exception e) {
            e.printStackTrace();
            mostrarAlerta(Alert.AlertType.ERROR, "Error de Navegación", "No se encontró la vista del menú.");
        }
    }

    private void mostrarAlerta(Alert.AlertType tipo, String titulo, String mensaje) {
        Alert alert = new Alert(tipo);
        alert.setTitle(titulo);
        alert.setHeaderText(null);
        alert.setContentText(mensaje);
        alert.showAndWait();
    }
}

package com.sistema.puntoventas.controller;

import com.sistema.puntoventas.modelo.Usuario;
import com.sistema.puntoventas.service.UsuarioService;
import javafx.fxml.FXML;
import javafx.scene.control.Alert;
import javafx.scene.control.Button;
import javafx.scene.control.PasswordField;
import javafx.scene.control.TextField;

public class LoginController {

    @FXML
    private TextField rutTextField;

    @FXML
    private PasswordField passwordField;

    @FXML
    private Button continuarButton;

    private UsuarioService usuarioService = new UsuarioService();

    @FXML
    public void handleLogin() {
        String rut = rutTextField.getText().trim();
        String password = passwordField.getText().trim();

        if (rut.isEmpty() || password.isEmpty()) {
            mostrarAlerta(Alert.AlertType.WARNING, "Campos vacíos",
                "Por favor, ingresa tu RUT y contraseña");
            return;
        }

        Usuario usuario = usuarioService.iniciarSesion(rut, password);
        if (usuario != null) {
            mostrarAlerta(Alert.AlertType.INFORMATION, "Login exitoso",
                "Bienvenido, " + usuario.getNombre() + " " + usuario.getApellido());
            // Aquí puedes cargar la siguiente vista, por ejemplo PanelProductos
        } else {
            mostrarAlerta(Alert.AlertType.ERROR, "Login fallido",
                "RUT o contraseña incorrectos");
        }
        passwordField.clear();
    }

    private void mostrarAlerta(Alert.AlertType tipo, String titulo, String mensaje) {
        Alert alert = new Alert(tipo);
        alert.setTitle(titulo);
        alert.setHeaderText(null);
        alert.setContentText(mensaje);
        alert.showAndWait();
    }
}
